// Rotate through topics or pull from your topic list
const topics = [
  'How CookieNet works — a 16-year-old's bedroom datacenter',
  'Why self-hosting beats the cloud',
  'Setting up Ubiquiti networking at home',
  'How I built a Kubernetes cluster in my bedroom',
  'What is Nextcloud and why you need it',
  'Open source AI models you can run locally',
  'How Tailscale makes private networking easy',
  'Building a Ceph storage cluster on a budget',
  'Why GrapheneOS is the most private Android',
  'How I removed Google from my life',
];
const today = new Date();
const idx   = today.getDate() % topics.length;
return [{ json: { topic: topics[idx], date: today.toISOString() } }];

